if(NebulaMgr.getFlagShow()) {
    core.debug("Deep-sky objects are visible");
} else {
    NebulaMgr.setFlagShow(true);
}

// Enable deep-sky objects
NebulaMgr.setFlagShow(true);

// Disable all deep-sky objects
NebulaMgr.setFlagShow(false);

// Toggle current state
var current = NebulaMgr.getFlagShow();
NebulaMgr.setFlagShow(!current);

if(NebulaMgr.getFlagHints()) {
    core.debug("Nebula hints are visible");
} else {
    NebulaMgr.setFlagHints(true);
}

// Show DSO hints
NebulaMgr.setFlagHints(true);

// Hide DSO hints (only labels visible)
NebulaMgr.setFlagHints(false);

// Show many DSO hints
NebulaMgr.setHintsAmount(8.0);

// Show only brightest DSOs
NebulaMgr.setHintsAmount(2.0);

// Show many DSO labels
NebulaMgr.setLabelsAmount(7.0);

// Show labels only for bright DSOs
NebulaMgr.setLabelsAmount(2.0);

// Dim hints for less visual clutter
NebulaMgr.setHintsBrightness(0.5);

// Full brightness hints
NebulaMgr.setHintsBrightness(1.0);

// Dim labels for less clutter
NebulaMgr.setLabelsBrightness(0.6);

// Full brightness labels
NebulaMgr.setLabelsBrightness(1.0);

// RECOMMENDED: Use StelProperty
var labelColor = core.getStelProperty('NebulaMgr.labelsColor');
core.debug("Labels color: " + labelColor);

// Alternative: Direct call
var colorObj = NebulaMgr.getLabelsColor();
var colorStr = String(colorObj); // '[R, G, B]'
var parts = colorStr.slice(1, -1).split(',').map(parseFloat);
core.debug("Labels color - R: " + parts[0] + ", G: " + parts[1] + ", B: " + parts[2]);

// Set labels to light blue
var lightBlue = core.vec3f(0.5, 0.7, 1.0);
NebulaMgr.setLabelsColor(lightBlue);

// Set labels to white
var white = core.vec3f(1.0, 1.0, 1.0);
NebulaMgr.setLabelsColor(white);

// Fast fade
NebulaMgr.setHintsFadeDuration(0.5);

// Slow dramatic fade
NebulaMgr.setHintsFadeDuration(2.0);

if(NebulaMgr.getHintsProportional()) {
    core.debug("Hints are proportional to object size");
}

// Enable proportional hints (large DSOs have larger symbols)
NebulaMgr.setHintsProportional(true);

// Use fixed-size hints
NebulaMgr.setHintsProportional(false);

// Show detailed outlines for large DSOs
NebulaMgr.setFlagOutlines(true);

// Use standard hint symbols
NebulaMgr.setFlagOutlines(false);

if(NebulaMgr.getFlagAdditionalNames()) {
    core.debug("Additional DSO names are displayed");
}

// Show all common names for DSOs
NebulaMgr.setFlagAdditionalNames(true);

// Show only primary names
NebulaMgr.setFlagAdditionalNames(false);

if(NebulaMgr.getDesignationUsage()) {
    core.debug("Catalog designations are shown instead of common names");
}

// Use catalog numbers (M31, NGC 224) for labels
NebulaMgr.setDesignationUsage(true);

// Use common names (Andromeda Galaxy) for labels
NebulaMgr.setDesignationUsage(false);

// Use surface brightness for better extended object visibility
NebulaMgr.setFlagSurfaceBrightnessUsage(true);

// Use standard magnitude
NebulaMgr.setFlagSurfaceBrightnessUsage(false);

if(NebulaMgr.getFlagSurfaceBrightnessShortNotationUsage()) {
    core.debug("Using short notation for surface brightness");
}

if(NebulaMgr.getFlagSizeLimitsUsage()) {
    core.debug("DSO size limits are active");
}

// Only show DSOs between min and max size
NebulaMgr.setFlagSizeLimitsUsage(true);
NebulaMgr.setMinSizeLimit(5.0);
NebulaMgr.setMaxSizeLimit(30.0);

// Disable size filtering
NebulaMgr.setFlagSizeLimitsUsage(false);

if(NebulaMgr.getFlagShowOnlyNamedDSO()) {
    core.debug("Only named DSOs are visible");
}

// Show only well-known named DSOs
NebulaMgr.setFlagShowOnlyNamedDSO(true);

// Show all DSOs (including anonymous ones)
NebulaMgr.setFlagShowOnlyNamedDSO(false);

// Enable type filtering
NebulaMgr.setFlagUseTypeFilters(true);
NebulaMgr.setTypeFilters(64); // Show only bright nebulae

// Disable type filtering (show all)
NebulaMgr.setFlagUseTypeFilters(false);

// Set circles to gold
var gold = core.vec3f(1.0, 0.84, 0.0);
NebulaMgr.setCirclesColor(gold);

// Set galaxies to red
var red = core.vec3f(1.0, 0.2, 0.2);
NebulaMgr.setGalaxyColor(red);

// Show only Messier and NGC catalogs
NebulaMgr.setCatalogFilters(4 | 1); // CatM (4) | CatNGC (1)

// Show all catalogs
NebulaMgr.selectAllCatalogs();

// Show only standard catalogs (M, NGC, IC)
NebulaMgr.selectStandardCatalogs();

// Disable all catalogs
NebulaMgr.selectNoneCatalogs();

// Show all DSO catalogs
NebulaMgr.selectAllCatalogs();
core.debug("All DSO catalogs enabled");

// Show only galaxies and star clusters
NebulaMgr.setTypeFilters(1 | 8); // TypeGalaxies (1) | TypeOpenStarClusters (8)

// Show all types
NebulaMgr.setTypeFilters(0xFFFFFFFF);

// Show only nebulae
NebulaMgr.setTypeFilters(64 | 128 | 256); // TypeBrightNebulae, TypeDarkNebulae, TypePlanetaryNebulae

// Find M31 (Andromeda Galaxy)
var m31 = NebulaMgr.searchM(31);
if(m31) {
    core.debug("Found M31: " + m31.getEnglishName());
    core.moveToObject("M31", 2);
}

// Find NGC 6992 (Veil Nebula)
var ngc6992 = NebulaMgr.searchNGC(6992);
if(ngc6992) {
    core.debug("Found NGC 6992");
}

// Find the Orion Nebula by name
var orionNebula = NebulaMgr.searchForCommonName("Orion Nebula");
if(orionNebula) {
    core.moveToObject(orionNebula.getEnglishName(), 2);
}

// Get all Messier objects
var messierObjects = NebulaMgr.getDeepSkyObjectsByType("100");
core.debug("Messier objects: " + messierObjects.length);

// Get all NGC objects
var ngcObjects = NebulaMgr.getDeepSkyObjectsByType("108");

// Get all galaxies (type 0)
var galaxies = NebulaMgr.getDeepSkyObjectsByType("0");

var core = StelApp.getCore();
var maxMag = NebulaMgr.computeMaxMagHint(core.getSkyDrawer());
core.debug("Hint display limit magnitude: " + maxMag);
